// NotebookDocumentServiceHandler is an implementation of the
// chalk.notebook.v1.NotebookDocumentService service.
type NotebookDocumentServiceHandler interface {
	CreateNotebookDocument(context.Context, *connect.Request[v1.CreateNotebookDocumentRequest]) (*connect.Response[v1.CreateNotebookDocumentResponse], error)
	GetNotebookDocument(context.Context, *connect.Request[v1.GetNotebookDocumentRequest]) (*connect.Response[v1.GetNotebookDocumentResponse], error)
	ListNotebookDocuments(context.Context, *connect.Request[v1.ListNotebookDocumentsRequest]) (*connect.Response[v1.ListNotebookDocumentsResponse], error)
	UpdateNotebookDocument(context.Context, *connect.Request[v1.UpdateNotebookDocumentRequest]) (*connect.Response[v1.UpdateNotebookDocumentResponse], error)
	// Returns the id of the Dashboard row backing this notebook's app view,
	// creating it (empty, owner_type="notebook") and linking it to the document
	// in one transaction on first call. Idempotent.
	EnsureNotebookApp(context.Context, *connect.Request[v1.EnsureNotebookAppRequest]) (*connect.Response[v1.EnsureNotebookAppResponse], error)
	DeleteNotebookDocument(context.Context, *connect.Request[v1.DeleteNotebookDocumentRequest]) (*connect.Response[v1.DeleteNotebookDocumentResponse], error)
	// Archives or restores a notebook by setting/clearing archived_at. Archived
	// notebooks are excluded from the default list (ListNotebookDocuments with
	// include_archived=false) but are not soft-deleted.
	SetNotebookArchived(context.Context, *connect.Request[v1.SetNotebookArchivedRequest]) (*connect.Response[v1.SetNotebookArchivedResponse], error)
	AddNotebookCell(context.Context, *connect.Request[v1.AddNotebookCellRequest]) (*connect.Response[v1.AddNotebookCellResponse], error)
	UpdateNotebookCell(context.Context, *connect.Request[v1.UpdateNotebookCellRequest]) (*connect.Response[v1.UpdateNotebookCellResponse], error)
	DeleteNotebookCell(context.Context, *connect.Request[v1.DeleteNotebookCellRequest]) (*connect.Response[v1.DeleteNotebookCellResponse], error)
	MoveNotebookCell(context.Context, *connect.Request[v1.MoveNotebookCellRequest]) (*connect.Response[v1.MoveNotebookCellResponse], error)
	BatchUpdateNotebookCells(context.Context, *connect.Request[v1.BatchUpdateNotebookCellsRequest]) (*connect.Response[v1.BatchUpdateNotebookCellsResponse], error)
	// Persists the run plan and launches execution server-side; execution is
	// not tied to any client connection. Observe progress via WatchNotebookRun.
	StartNotebookRun(context.Context, *connect.Request[v1.StartNotebookRunRequest]) (*connect.Response[v1.StartNotebookRunResponse], error)
	// Replays persisted events for the run, then tails live events until the
	// run reaches a terminal state. Safe to call repeatedly and from multiple
	// clients; reconnect with after_sequence to skip already-seen output.
	WatchNotebookRun(context.Context, *connect.Request[v1.WatchNotebookRunRequest], *connect.ServerStream[v1.WatchNotebookRunResponse]) error
	InterruptNotebookRun(context.Context, *connect.Request[v1.InterruptNotebookRunRequest]) (*connect.Response[v1.InterruptNotebookRunResponse], error)
	ListNotebookCellResults(context.Context, *connect.Request[v1.ListNotebookCellResultsRequest]) (*connect.Response[v1.ListNotebookCellResultsResponse], error)
	// Pages through the full data behind a dataframe output chunk (blob-backed
	// Arrow artifacts, inline previews, SQL results), beyond the persisted
	// preview rows.
	FetchNotebookDataframeRows(context.Context, *connect.Request[v1.FetchNotebookDataframeRowsRequest]) (*connect.Response[v1.FetchNotebookDataframeRowsResponse], error)
	// Reduces one column of a dataframe output chunk to a single value over the
	// FULL backing artifact (blob-backed Arrow, inline arrow bytes) — used by
	// single-value elements whose source is larger than the persisted preview.
	AggregateNotebookDataframe(context.Context, *connect.Request[v1.AggregateNotebookDataframeRequest]) (*connect.Response[v1.AggregateNotebookDataframeResponse], error)
	// Streams the complete dataframe behind an output chunk for download —
	// the full backing data, never just the preview rows.
	DownloadNotebookDataframe(context.Context, *connect.Request[v1.DownloadNotebookDataframeRequest], *connect.ServerStream[v1.DownloadNotebookDataframeResponse]) error
	ListNotebookCellRunHistory(context.Context, *connect.Request[v1.ListNotebookCellRunHistoryRequest]) (*connect.Response[v1.ListNotebookCellRunHistoryResponse], error)
	ListNotebookDocumentRevisions(context.Context, *connect.Request[v1.ListNotebookDocumentRevisionsRequest]) (*connect.Response[v1.ListNotebookDocumentRevisionsResponse], error)
	ListNotebookRuns(context.Context, *connect.Request[v1.ListNotebookRunsRequest]) (*connect.Response[v1.ListNotebookRunsResponse], error)
	GetNotebookRunDetails(context.Context, *connect.Request[v1.GetNotebookRunDetailsRequest]) (*connect.Response[v1.GetNotebookRunDetailsResponse], error)
	ClearNotebookCellResults(context.Context, *connect.Request[v1.ClearNotebookCellResultsRequest]) (*connect.Response[v1.ClearNotebookCellResultsResponse], error)
	GetNotebookSqlCacheSettings(context.Context, *connect.Request[v1.GetNotebookSqlCacheSettingsRequest]) (*connect.Response[v1.GetNotebookSqlCacheSettingsResponse], error)
	// Environment-wide cache policy is the admin knob; notebook/cell overrides
	// ride UpdateNotebookDocument/UpdateNotebookCell at editor tier.
	UpdateNotebookSqlCacheSettings(context.Context, *connect.Request[v1.UpdateNotebookSqlCacheSettingsRequest]) (*connect.Response[v1.UpdateNotebookSqlCacheSettingsResponse], error)
	// Provisions (or returns the existing) kernel runtime for a notebook: a
	// notebooks runtime row plus a chalk_nb_server container bound to this
	// notebook's session id. Idempotent — a second call returns the current
	// status without creating a duplicate container. Container creation is
	// synchronous but readiness (a routable web URL) is asynchronous, so a fresh
	// provision returns PROVISIONING and callers poll GetNotebookRuntimeStatus.
	StartNotebookRuntime(context.Context, *connect.Request[v1.StartNotebookRuntimeRequest]) (*connect.Response[v1.StartNotebookRuntimeResponse], error)
	// Stops the runtime container and marks the notebooks row stopped. Idempotent.
	StopNotebookRuntime(context.Context, *connect.Request[v1.StopNotebookRuntimeRequest]) (*connect.Response[v1.StopNotebookRuntimeResponse], error)
	GetNotebookRuntimeStatus(context.Context, *connect.Request[v1.GetNotebookRuntimeStatusRequest]) (*connect.Response[v1.GetNotebookRuntimeStatusResponse], error)
	// Streams the notebook's kernel runtime status: sends the current status
	// immediately on subscribe, then a new message each time the derived state
	// (or its error detail / web-url presence) changes, until the client
	// disconnects. Backend-owned readiness the frontend subscribes to instead of
	// polling GetNotebookRuntimeStatus, so kernel-dependent queries can gate on a
	// READY state rather than racing a booting kernel.
	WatchNotebookRuntimeStatus(context.Context, *connect.Request[v1.WatchNotebookRuntimeStatusRequest], *connect.ServerStream[v1.WatchNotebookRuntimeStatusResponse]) error
	// Lists live kernel runtimes (non-stopped notebooks with a non-stopped
	// backing container) in the request's environment. State is resolved per row
	// the same way GetNotebookRuntimeStatus resolves it for a single notebook.
	ListNotebookRuntimes(context.Context, *connect.Request[v1.ListNotebookRuntimesRequest]) (*connect.Response[v1.ListNotebookRuntimesResponse], error)
	// Lists the Python packages installed in a notebook's running kernel by
	// proxying to the kernel's ListInstalledPackages RPC (cached per container).
	ListNotebookKernelPackages(context.Context, *connect.Request[v1.ListNotebookKernelPackagesRequest]) (*connect.Response[v1.ListNotebookKernelPackagesResponse], error)
	// Assembles the notebook's variable data-flow DAG: nodes are runnable cells,
	// edges are last-producer-wins dependencies. Provides/requires come from the
	// kernel's AST analysis (AnalyzeNotebookCellDependencies), not a server-side
	// line parser. Returns an empty graph when no kernel runtime is reachable.
	GetNotebookDependencyGraph(context.Context, *connect.Request[v1.GetNotebookDependencyGraphRequest]) (*connect.Response[v1.GetNotebookDependencyGraphResponse], error)
	ListNotebookSecrets(context.Context, *connect.Request[v1.ListNotebookSecretsRequest]) (*connect.Response[v1.ListNotebookSecretsResponse], error)
	GetNotebookSecretValue(context.Context, *connect.Request[v1.GetNotebookSecretValueRequest]) (*connect.Response[v1.GetNotebookSecretValueResponse], error)
	UpsertNotebookSecret(context.Context, *connect.Request[v1.UpsertNotebookSecretRequest]) (*connect.Response[v1.UpsertNotebookSecretResponse], error)
	DeleteNotebookSecret(context.Context, *connect.Request[v1.DeleteNotebookSecretRequest]) (*connect.Response[v1.DeleteNotebookSecretResponse], error)
}

